import { Link } from "react-router-dom";
import StatusDetails from "../../utils/StatusDetails";
import StatusDrop from "../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { epochTogmt } from "../../utils/Common";
import authService from "src/auth/auth.service";

export const tableTestimonialConstant = (getTestimonialList, handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Name",
            cell: (row) => {
                return (
                    <Link to={`/testimonial/edit/${row?._id}`}>
                        <span className="sub">{row.name}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Company",
            selector: (row) => row.company
        },
        {
            id: 3,
            name: "Ratings",
            selector: (row) => row.rating
        },
        {
            id: 4,
            name: "Created Date",
            selector: (row) => epochTogmt(row.createdAt)
        },
        {
            id: 5,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 9,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row._id}
                        status={row.status}
                        type={'TESTIMONIAL'}
                        action={getTestimonialList}
                        key={uuidv4()}
                        publishPermission={""}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 4,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row._id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
